// Egress validation for the background deep-research report, then chunk for
// Telegram. Mirrors the Agent Router's 'Egress Validation' (reject exec/eval,
// strip <script>, redact non-allowlisted URLs in the body, preserve a trailing
// [[SOURCES]] block deduped+capped). The router never sees this path (the report
// is self-sent to Telegram), so the same gate is applied here. Output: one item
// per Telegram-sized chunk (<=3500 chars). The sources block is always emitted
// as its own trailing chunk so it is never dropped by the body chunk cap.
const item = $input.first().json;
let reply = (item.output !== undefined && item.output !== null) ? item.output : ((item.text !== undefined && item.text !== null) ? item.text : '');
reply = String(reply);
if (/exec\s*\(|eval\s*\(/i.test(reply)) {
  return [{ json: { chunk: '\ud83d\udd0e \u05d4\u05de\u05d7\u05e7\u05e8 \u05e0\u05d7\u05e1\u05dd \u05e2\"\u05d9 \u05de\u05d3\u05d9\u05e0\u05d9\u05d5\u05ea egress.', idx: 0, total: 1 } }];
}
reply = reply.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<\/?script[^>]*>/gi, '');
const ALLOW = /(^|\.)(or-infra\.com|openrouter\.ai|n8n\.io|github\.com|railway\.app|railway\.com)$/i;
const redactBody = function (text) {
  return text.replace(/https?:\/\/[^\s<>"')]+/gi, function (u) {
    try { return ALLOW.test(new URL(u).hostname) ? u : '[redacted-url]'; }
    catch (e) { return '[redacted-url]'; }
  });
};
const MARK = '[[SOURCES]]';
const at = reply.indexOf(MARK);
const body = redactBody(at >= 0 ? reply.slice(0, at) : reply).replace(/\s+$/, '');
let sourcesBlock = '';
if (at >= 0) {
  const tail = reply.slice(at + MARK.length);
  const found = tail.match(/https?:\/\/[^\s<>"')\]]+/gi) || [];
  const seen = {};
  const urls = [];
  for (let i = 0; i < found.length; i++) {
    const u = found[i].replace(/[.,;)\]]+$/, '');
    const key = u.toLowerCase();
    if (!seen[key]) { seen[key] = true; urls.push(u); }
    if (urls.length >= 10) { break; }
  }
  if (urls.length) {
    const lines = ['\u05de\u05e7\u05d5\u05e8\u05d5\u05ea:'];
    for (let j = 0; j < urls.length; j++) { lines.push((j + 1) + '. ' + urls[j]); }
    sourcesBlock = lines.join('\n');
  }
}
if ((!body || !body.trim()) && !sourcesBlock) {
  return [{ json: { chunk: '\ud83d\udd0e \u05dc\u05d0 \u05d4\u05e6\u05dc\u05d7\u05ea\u05d9 \u05dc\u05d4\u05e4\u05d9\u05e7 \u05ea\u05d5\u05e6\u05d0\u05ea \u05de\u05d7\u05e7\u05e8 \u05d4\u05e4\u05e2\u05dd \u2014 \u05e0\u05e1\u05d4 \u05e9\u05d5\u05d1.', idx: 0, total: 1 } }];
}
const LIMIT = 3500;
const MAXBODY = 3;
const chunks = [];
let rest = '\ud83d\udd0e \u05d4\u05de\u05d7\u05e7\u05e8 \u05de\u05d5\u05db\u05df:\n\n' + (body && body.trim() ? body : '(\u05d0\u05d9\u05df \u05ea\u05d5\u05db\u05df)');
while (rest.length > LIMIT && chunks.length < MAXBODY - 1) {
  let cut = rest.lastIndexOf('\n', LIMIT);
  if (cut < Math.floor(LIMIT * 0.6)) { cut = LIMIT; }
  chunks.push(rest.slice(0, cut));
  rest = rest.slice(cut).replace(/^\n+/, '');
}
if (rest.length > LIMIT) { rest = rest.slice(0, LIMIT - 1) + '\u2026'; }
chunks.push(rest);
if (sourcesBlock) {
  let sb = sourcesBlock.length > LIMIT ? (sourcesBlock.slice(0, LIMIT - 1) + '\u2026') : sourcesBlock;
  chunks.push(sb);
}
return chunks.map(function (c, i) { return { json: { chunk: c, idx: i, total: chunks.length } }; });
